import React, { useState, useEffect } from 'react';
import { useUI } from '../../context/UIContext';
import { AlertCircle, CheckCircle2, Info, X, HelpCircle, Lock } from 'lucide-react';

const GlobalModal = () => {
    const { modalConfig } = useUI();
    const [inputValue, setInputValue] = useState('');

    const [prevModal, setPrevModal] = useState(modalConfig);
    if (modalConfig !== prevModal) {
        setPrevModal(modalConfig);
        if (modalConfig?.type === 'prompt') {
            setInputValue('');
        }
    }

    if (!modalConfig) return null;

    const { type, inputType, title, message, alertType, confirmText, variant, onConfirm, onCancel, onClose } = modalConfig;

    const getIcon = () => {
        if (type === 'prompt') return <Lock className="text-indigo-500" size={32} />;
        if (type === 'confirm') return <HelpCircle className="text-amber-500" size={32} />;
        switch (alertType) {
            case 'success': return <CheckCircle2 className="text-emerald-500" size={32} />;
            case 'error': return <AlertCircle className="text-rose-500" size={32} />;
            default: return <Info className="text-indigo-500" size={32} />;
        }
    };

    return (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 sm:p-6 animate-in fade-in duration-200">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
                onClick={type === 'alert' ? onClose : onCancel}
            ></div>

            {/* Modal Card */}
            <div className="relative w-full max-w-md bg-white rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 border border-slate-100">
                <div className="p-8">
                    <div className="flex flex-col items-center text-center">
                        <div className="mb-4 p-4 bg-slate-50 rounded-2xl">
                            {getIcon()}
                        </div>

                        <h3 className="text-xl font-extrabold text-slate-800 mb-2 tracking-tight">
                            {title}
                        </h3>

                        <p className="text-slate-500 leading-relaxed">
                            {message}
                        </p>
                    </div>

                    <div className="mt-8 flex flex-col gap-3">
                        {type === 'prompt' ? (
                            <>
                                <input
                                    type={inputType || 'text'}
                                    value={inputValue}
                                    onChange={(e) => setInputValue(e.target.value)}
                                    // Submit on enter
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter') onConfirm(inputValue);
                                    }}
                                    className="w-full p-4 mb-2 border-2 border-slate-200 rounded-xl focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 focus:outline-none transition-all text-sm font-medium"
                                    placeholder={inputType === 'password' ? '••••••••' : 'Enter value...'}
                                    autoFocus
                                />
                                <button
                                    onClick={() => onConfirm(inputValue)}
                                    className={`w-full py-3.5 px-6 rounded-2xl text-sm font-bold text-white shadow-lg transition-all active:scale-95 ${variant === 'danger'
                                        ? 'bg-rose-600 hover:bg-rose-700 shadow-rose-200'
                                        : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
                                        }`}
                                >
                                    {confirmText || 'Submit'}
                                </button>
                                <button
                                    onClick={onCancel}
                                    className="w-full py-3.5 px-6 rounded-2xl text-sm font-bold text-slate-600 bg-slate-50 hover:bg-slate-100 transition-all active:scale-95"
                                >
                                    Cancel
                                </button>
                            </>
                        ) : type === 'confirm' ? (
                            <>
                                <button
                                    onClick={onConfirm}
                                    className={`w-full py-3.5 px-6 rounded-2xl text-sm font-bold text-white shadow-lg transition-all active:scale-95 ${variant === 'danger'
                                        ? 'bg-rose-600 hover:bg-rose-700 shadow-rose-200'
                                        : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
                                        }`}
                                >
                                    {confirmText || 'Confirm'}
                                </button>
                                <button
                                    onClick={onCancel}
                                    className="w-full py-3.5 px-6 rounded-2xl text-sm font-bold text-slate-600 bg-slate-50 hover:bg-slate-100 transition-all active:scale-95"
                                >
                                    Cancel
                                </button>
                            </>
                        ) : (
                            <button
                                onClick={onClose}
                                className="w-full py-3.5 px-6 rounded-2xl text-sm font-bold text-white bg-slate-900 hover:bg-slate-800 shadow-lg shadow-slate-200 transition-all active:scale-95"
                            >
                                Got it
                            </button>
                        )}
                    </div>
                </div>

                {/* Decorative border at top */}
                <div className={`absolute top-0 left-0 w-full h-1.5 ${type === 'confirm' ? 'bg-amber-400' :
                    type === 'prompt' ? 'bg-indigo-400' :
                        alertType === 'success' ? 'bg-emerald-400' :
                            alertType === 'error' ? 'bg-rose-400' : 'bg-indigo-400'
                    }`}></div>
            </div>
        </div>
    );
};

export default GlobalModal;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useOutletContext, useNavigate } from 'react-router-dom';
import api from '../services/api';
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    LineChart, Line, PieChart, Pie, Cell, AreaChart, Area, Legend
} from 'recharts';
import {
    Users, IndianRupee, ShoppingBag, TrendingUp, TrendingDown,
    Activity, Package, CreditCard, AlertCircle, Headphones
} from 'lucide-react';

import SuperAdminDashboard from './super-admin/SuperAdminDashboard';
import ReportsWidget from '../components/dashboard/ReportsWidget';

export default function DashboardHome() {
    const { user } = useAuth();

    // State
    const [stats, setStats] = useState({
        employees: 0,
        revenue: 0,
        expenses: 0,
        profit: 0,
        productsSold: 0
    });
    const [chartData, setChartData] = useState({
        revenueVsExpenses: [],
        salesTrend: [],
        topProducts: []
    });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!user) return;
        fetchDashboardData();
    }, [user]);

    const fetchDashboardData = async () => {
        try {
            const companyId = localStorage.getItem('companyId');

            // Parallel Fetch
            const [empRes, invRes, expRes, salaryRes] = await Promise.all([
                api.get('/employees', { params: { companyId } }),
                api.get('/invoices', { params: { companyId } }),
                api.get('/expenses', { params: { companyId } }),
                api.get('/employees/salary-records', { params: { companyId } })
            ]);

            const employees = empRes.data;
            const invoices = invRes.data;
            const expenses = expRes.data;
            const salaryRecords = salaryRes.data;

            // --- KPI CALCULATIONS ---
            const totalEmployees = employees.length;

            // Revenue (Only PAID invoices)
            const paidInvoices = invoices.filter(i => i.status === 'PAID');
            const totalRevenue = paidInvoices.reduce((sum, i) => sum + (i.grandTotal || 0), 0);

            // Expenses (exclude mirrored Payroll category if redundant)
            const sumGeneralExpenses = expenses.filter(e => e.category !== 'Payroll').reduce((sum, e) => sum + (e.amount || 0), 0);
            const sumPayroll = salaryRecords.reduce((sum, s) => sum + (s.amount || 0), 0);
            const totalExpenses = sumGeneralExpenses + sumPayroll;

            // Profit
            const netProfit = totalRevenue - totalExpenses;

            // Products Sold (Sum quantity of items in PAID invoices)
            const totalProductsSold = paidInvoices.reduce((sum, inv) => {
                const itemsCount = inv.items?.reduce((isum, item) => isum + (parseInt(item.quantity) || 0), 0) || 0;
                return sum + itemsCount;
            }, 0);

            setStats({
                employees: totalEmployees,
                revenue: totalRevenue,
                expenses: totalExpenses,
                profit: netProfit,
                productsSold: totalProductsSold
            });

            // --- CHART DATA PREPARATION ---
            // 1. Revenue vs Expenses (Last 6 Months)
            const months = {};
            const today = new Date();
            for (let i = 5; i >= 0; i--) {
                const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
                const key = d.toLocaleString('default', { month: 'short' });
                months[key] = { name: key, revenue: 0, expenses: 0 };
            }

            paidInvoices.forEach(inv => {
                const d = new Date(inv.date || inv.createdAt);
                const key = d.toLocaleString('default', { month: 'short' });
                if (months[key]) months[key].revenue += (inv.grandTotal || 0);
            });

            expenses.filter(e => e.category !== 'Payroll').forEach(exp => {
                const d = new Date(exp.date || exp.createdAt);
                const key = d.toLocaleString('default', { month: 'short' });
                if (months[key]) months[key].expenses += (exp.amount || 0);
            });

            salaryRecords.forEach(s => {
                const d = new Date(s.paymentDate || s.createdAt);
                const key = d.toLocaleString('default', { month: 'short' });
                if (months[key]) months[key].expenses += (s.amount || 0);
            });

            const revenueData = Object.values(months);

            // 2. Top Products
            const productMap = {};
            paidInvoices.forEach(inv => {
                inv.items?.forEach(item => {
                    const name = item.description || 'Unknown Item';
                    if (!productMap[name]) productMap[name] = 0;
                    productMap[name] += parseInt(item.quantity) || 0;
                });
            });
            const topProducts = Object.entries(productMap)
                .map(([name, value]) => ({ name, value }))
                .sort((a, b) => b.value - a.value)
                .slice(0, 5); // Top 5

            setChartData({
                revenueVsExpenses: revenueData,
                topProducts: topProducts,
                salesTrend: []
            });

        } catch (err) {
            console.error("Failed to load dashboard data", err);
        } finally {
            setLoading(false);
        }
    };

    const formatCurrency = (val) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(val);

    if (loading) return <div className="p-10 text-center animate-pulse">Loading Dashboard...</div>;

    // Super Admin View Redirect
    if (user.isSuperAdmin) {
        return <SuperAdminDashboard />;
    }

    return (
        <div className="space-y-8">
            {/* HEADER */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center">
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">Company Overview</h1>
                    <p className="text-slate-500 mt-1">Real-time performance metrics and insights.</p>
                </div>
                <div className="bg-white px-4 py-2 rounded-lg border border-slate-200 text-sm text-slate-600 shadow-sm">
                    {new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                </div>
            </div>

            {/* KPI CARDS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <KPICard
                    title="Total Revenue"
                    value={formatCurrency(stats.revenue)}
                    icon={<IndianRupee size={24} className="text-white" />}
                    color="bg-gradient-to-r from-blue-500 to-blue-600"
                    subtext="Lifetime earnings"
                />
                <KPICard
                    title="Net Profit"
                    value={formatCurrency(stats.profit)}
                    icon={<TrendingUp size={24} className="text-white" />}
                    color={stats.profit >= 0 ? "bg-gradient-to-r from-emerald-500 to-emerald-600" : "bg-gradient-to-r from-red-500 to-red-600"}
                    subtext="Revenue - Expenses"
                />
                <KPICard
                    title="Products Sold"
                    value={stats.productsSold}
                    icon={<ShoppingBag size={24} className="text-white" />}
                    color="bg-gradient-to-r from-purple-500 to-purple-600"
                    subtext="Total items shipped"
                />
                <KPICard
                    title="Total Employees"
                    value={stats.employees}
                    icon={<Users size={24} className="text-white" />}
                    color="bg-gradient-to-r from-amber-500 to-amber-600"
                    subtext="Active team members"
                />
            </div>

            {/* MAIN CHARTS ROW */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* REVENUE VS EXPENSES */}
                <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                    <h3 className="text-lg font-bold text-slate-800 mb-6">Financial Performance (6 Months)</h3>
                    <div className="h-80 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={chartData.revenueVsExpenses}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                                <YAxis axisLine={false} tickLine={false} />
                                <Tooltip
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                                    cursor={{ fill: '#f8fafc' }}
                                />
                                <Legend />
                                <Bar dataKey="revenue" name="Revenue" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={30} />
                                <Bar dataKey="expenses" name="Expenses" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={30} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* TOP PRODUCTS */}
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col">
                    <h3 className="text-lg font-bold text-slate-800 mb-2">Top Selling Products</h3>
                    <p className="text-sm text-slate-500 mb-6">Based on quantity sold.</p>
                    <div className="flex-grow">
                        {chartData.topProducts.length > 0 ? (
                            <div className="h-64 w-full">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={chartData.topProducts}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={60}
                                            outerRadius={80}
                                            paddingAngle={5}
                                            dataKey="value"
                                        >
                                            {chartData.topProducts.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'][index % 5]} />
                                            ))}
                                        </Pie>
                                        <Tooltip />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        ) : (
                            <div className="h-full flex items-center justify-center text-slate-400 text-sm">No sales data yet</div>
                        )}
                    </div>
                    <div className="mt-4 space-y-3">
                        {chartData.topProducts.map((item, idx) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                                <div className="flex items-center gap-2">
                                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'][idx % 5] }}></div>
                                    <span className="text-slate-600 truncate max-w-[150px]">{item.name}</span>
                                </div>
                                <span className="font-bold text-slate-900">{item.value}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* BOTTOM ACTIVITY / REPORTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 bg-gradient-to-br from-indigo-700 to-indigo-900 rounded-xl p-6 text-white relative overflow-hidden shadow-lg border border-indigo-600/20">
                    <div className="relative z-10 flex flex-col h-full justify-center">
                        <div className="flex items-center gap-3 mb-3">
                            <div className="p-2 bg-white/10 rounded-lg backdrop-blur-sm">
                                <Headphones size={24} className="text-white" />
                            </div>
                            <h3 className="text-xl font-bold">Customer Care</h3>
                        </div>
                        <p className="text-indigo-100 text-sm mb-6 max-w-sm leading-relaxed">
                            Need help with your account or having technical issues? Contact our dedicated support team directly. We're here to assist you with any work or queries.
                        </p>
                        <a
                            href="mailto:yvo.company@gmail.com?subject=Support%20Request%20-%20"
                            className="inline-flex items-center justify-center w-fit bg-white text-indigo-900 px-6 py-2.5 rounded-lg text-sm font-bold hover:bg-slate-100 transition shadow-md"
                        >
                            Email Support
                        </a>
                    </div>
                    <Headphones className="absolute right-[-10px] bottom-[-10px] text-white opacity-5 w-44 h-44 -rotate-12" />
                </div>

                <div className="lg:col-span-1">
                    <ReportsWidget />
                </div>
            </div>
        </div>
    );
}

const KPICard = ({ title, value, icon, subtext, color }) => (
    <div className="bg-white rounded-xl border border-slate-200 p-6 shadow-sm flex items-start justify-between hover:shadow-md transition-shadow">
        <div>
            <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
            <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
            <p className="text-xs text-slate-400 mt-1">{subtext}</p>
        </div>
        <div className={`p-3 rounded-xl shadow-lg ${color}`}>
            {icon}
        </div>
    </div>
);

import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";
import { Link, useNavigate } from "react-router-dom";

const inputClassName =
  "mt-2 w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500";

const phoneInputClassName =
  "flex-1 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500";



export default function Login() {
  const navigate = useNavigate();

  const loginMethod = "phone"; // Default to phone

  const [email, setEmail] = useState("");
  const [emailPassword, setEmailPassword] = useState("");

  const [countryCode, setCountryCode] = useState("+91");
  const [phone, setPhone] = useState("");
  const [phonePassword, setPhonePassword] = useState("");



  const [submitting, setSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const { login, loginEmployee } = useAuth();

  const canSubmit = loginMethod === "email" ? email && emailPassword : phone && phonePassword;

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg("");
    setSubmitting(true);
    console.log("Submitting Login:", loginMethod);

    try {
      if (loginMethod === "phone") {
        console.log("Attempting Employee Login...", countryCode + phone);
        await loginEmployee(countryCode + phone, phonePassword);
        console.log("Employee Login Success, Navigating...");
        navigate("/employee-dashboard", { replace: true });
        return;
      }

      console.log("Attempting Admin Login...", email);
      const userData = await login(email, emailPassword);

      // STRICT SEPARATION: Block Super Admin
      if (userData.isSuperAdmin || userData.role === 'SUPER_ADMIN') {
        // Generic error to prevent role enumeration
        throw new Error("Invalid email or password");
      }
      console.log("Admin Login Success, Navigating...");
      navigate("/dashboard", { replace: true });
    } catch (err) {
      console.error("Login Error:", err);
      setErrorMsg(err?.response?.data?.message || err.message || "Something went wrong");
    } finally {
      setSubmitting(false);
    }
  };



  return (
    <div className="min-h-screen bg-slate-50 text-slate-700">
      <header className="border-b border-slate-200 bg-white">
        <div className="mx-auto flex w-full max-w-6xl items-center gap-3 px-6 py-4">
          <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-blue-600 text-lg font-semibold text-white shadow">
            Yo
          </div>
          <span className="text-lg font-semibold text-blue-700">YVO</span>
        </div>
      </header>

      <main className="mx-auto flex w-full max-w-6xl flex-1 flex-col items-center px-6 py-16">
        <div className="w-full max-w-md rounded-2xl border border-slate-200 bg-white p-8 shadow-sm">
          <div className="space-y-2 text-center">
            <h1 className="text-2xl font-semibold text-slate-900">
              {loginMethod === 'phone' ? 'Employee Login' : 'Admin Login'}
            </h1>
            <p className="text-sm text-slate-500">Sign in to your account</p>
          </div>

          {errorMsg && (
            <div className="mt-5 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
              {errorMsg}
            </div>
          )}

          {/* NORMAL LOGIN FORM */}
          <form className="space-y-4 mt-6" onSubmit={handleSubmit}>

            {/* HIDDEN TOGGLE - REPLACED WITH LINK BELOW */}
            {/* <div className="rounded-lg bg-slate-100 p-1"> ... </div> */}

            {loginMethod === "email" ? (
              <>
                <input
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  type="email"
                  placeholder="Email"
                  className={inputClassName}
                />
                <input
                  value={emailPassword}
                  onChange={(e) => setEmailPassword(e.target.value)}
                  type={showPassword ? "text" : "password"}
                  placeholder="Password"
                  className={inputClassName}
                />
              </>
            ) : (
              <>
                <div className="flex gap-2">
                  <select
                    value={countryCode}
                    onChange={(e) => setCountryCode(e.target.value)}
                    className="w-28 rounded-lg border border-slate-200 px-2 py-2"
                  >
                    <option value="+91">+91</option>
                    <option value="+1">+1</option>
                  </select>
                  <input
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    placeholder="Phone"
                    className={phoneInputClassName}
                  />
                </div>
                <input
                  value={phonePassword}
                  onChange={(e) => setPhonePassword(e.target.value)}
                  type={showPassword ? "text" : "password"}
                  placeholder="Password"
                  className={inputClassName}
                />
              </>
            )}

            <button
              type="submit"
              disabled={!canSubmit}
              className={`w-full rounded-lg px-3 py-2 text-sm font-semibold text-white ${canSubmit ? "bg-blue-600" : "bg-slate-300"
                }`}
            >
              {submitting ? "Logging in..." : "Login"}
            </button>

          </form>
        </div>
      </main>
    </div>
  );
}

import React, { useEffect, useState, useRef, useCallback } from 'react';
import api from '../../services/api';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Clock, ArrowLeft, ArrowRight, X } from 'lucide-react';

export default function EmployeeCalendar() {
    const [events, setEvents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [currentDate, setCurrentDate] = useState(new Date());
    const [selectedEvent, setSelectedEvent] = useState(null); // For modal
    const scrollRef = useRef(null);

    const fetchEvents = useCallback(async () => {
        try {
            const res = await api.get('/employee/dashboard/calendar');
            setEvents(res.data);
        } catch (error) {
            console.error("Error fetching calendar", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchEvents();
    }, [fetchEvents]);

    // Calendar Helpers
    const getDaysInMonth = (date) => {
        return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
    };

    const getFirstDayOfMonth = (date) => {
        return new Date(date.getFullYear(), date.getMonth(), 1).getDay();
    };

    const prevMonth = () => {
        setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    };

    const nextMonth = () => {
        setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    };

    const scrollLeft = () => {
        if (scrollRef.current) {
            scrollRef.current.scrollBy({ left: -200, behavior: 'smooth' });
        }
    };

    const scrollRight = () => {
        if (scrollRef.current) {
            scrollRef.current.scrollBy({ left: 200, behavior: 'smooth' });
        }
    };

    const renderCalendarGrid = () => {
        const daysInMonth = getDaysInMonth(currentDate);
        const firstDay = getFirstDayOfMonth(currentDate);
        const days = [];

        // Empty cells for previous month
        for (let i = 0; i < firstDay; i++) {
            days.push(<div key={`empty-${i}`} className="h-32 bg-slate-50 border border-slate-100"></div>);
        }

        // Days of current month
        for (let day = 1; day <= daysInMonth; day++) {
            const dateStr = new Date(currentDate.getFullYear(), currentDate.getMonth(), day).toDateString();
            const dayEvents = events.filter(e => new Date(e.start).toDateString() === dateStr);
            const isToday = new Date().toDateString() === dateStr;

            days.push(
                <div key={day} className={`h-32 border border-slate-100 p-2 overflow-y-auto hover:bg-slate-50 transition-colors ${isToday ? 'bg-blue-50/30' : 'bg-white'}`}>
                    <div className="flex justify-between items-start mb-1">
                        <span className={`text-sm font-medium rounded-full w-7 h-7 flex items-center justify-center ${isToday ? 'bg-indigo-600 text-white' : 'text-slate-700'}`}>
                            {day}
                        </span>
                    </div>
                    <div className="space-y-1">
                        {dayEvents.map(event => (
                            <div
                                key={event._id}
                                onClick={(e) => { e.stopPropagation(); setSelectedEvent(event); }}
                                className={`text-xs p-1.5 rounded border border-l-2 mb-1 cursor-pointer truncate hover:opacity-80 transition-opacity
                                    ${event.type === 'Meeting' ? 'bg-purple-50 border-purple-100 border-l-purple-500 text-purple-700' :
                                        event.type === 'Holiday' ? 'bg-sky-50 border-sky-100 border-l-sky-500 text-sky-700' :
                                            'bg-indigo-50 border-indigo-100 border-l-indigo-500 text-indigo-700'}`}
                                title="Click to view details"
                            >
                                <div className="font-medium truncate">{event.title}</div>
                                {event.start && (
                                    <div className="text-[10px] opacity-80">
                                        {new Date(event.start).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            );
        }

        return days;
    };

    const monthNames = ["January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December"
    ];

    if (loading) return (
        <div className="flex flex-col items-center justify-center min-h-[400px] space-y-4">
            <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-500 font-medium animate-pulse">Loading calendar...</p>
        </div>
    );

    return (
        <div className="space-y-6 animate-in fade-in duration-500 pb-16">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl md:text-3xl font-semibold text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-indigo-50 text-indigo-600 rounded-xl">
                            <CalendarIcon size={24} />
                        </div>
                        Events & Holidays
                    </h1>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
                    <div className="flex items-center bg-white border-2 border-slate-100 rounded-2xl shadow-sm w-full md:w-auto overflow-hidden">
                        <button onClick={prevMonth} className="p-3 hover:bg-slate-50 text-slate-400 hover:text-slate-900 transition-colors border-r border-slate-50">
                            <ChevronLeft size={20} strokeWidth={2} />
                        </button>
                        <span className="px-6 py-2.5 font-semibold text-slate-900 min-w-[140px] text-center flex-1 md:flex-none text-sm uppercase tracking-widest">
                            {monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}
                        </span>
                        <button onClick={nextMonth} className="p-3 hover:bg-slate-50 text-slate-400 hover:text-slate-900 transition-colors border-l border-slate-50">
                            <ChevronRight size={20} strokeWidth={2} />
                        </button>
                    </div>
                </div>
            </div>

            <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden flex flex-col h-full">
                <div className="overflow-x-auto [&::-webkit-scrollbar]:hidden snap-x snap-mandatory" ref={scrollRef}>
                    <div className="min-w-[700px]">
                        {/* Days Header */}
                        <div className="grid grid-cols-7 bg-slate-50/50 border-b border-slate-100">
                            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                                <div key={day} className="py-4 text-center text-[10px] font-semibold text-slate-400 uppercase tracking-[0.2em]">
                                    {day}
                                </div>
                            ))}
                        </div>

                        {/* Grid */}
                        <div className="grid grid-cols-7 bg-slate-100 gap-[1px]">
                            {renderCalendarGrid()}
                        </div>
                    </div>
                </div>
            </div>

            {/* Hint for mobile */}
            <div className="md:hidden flex items-center justify-center gap-2 text-slate-400 animate-pulse">
                <ArrowLeft size={14} />
                <span className="text-[10px] font-semibold uppercase tracking-widest">Swipe for full grid</span>
                <ArrowRight size={14} />
            </div>

            {/* Event Details Modal */}
            {selectedEvent && (
                <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm flex items-end md:items-center justify-center p-0 md:p-4 z-50 animate-in fade-in duration-300">
                    <div className="bg-white rounded-t-3xl md:rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in slide-in-from-bottom-full md:slide-in-from-bottom-4 duration-300">
                        <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-white">
                            <h3 className="font-semibold text-slate-900 flex items-center gap-2">
                                <CalendarIcon size={18} className="text-indigo-600" />
                                Event Details
                            </h3>
                            <button
                                onClick={() => setSelectedEvent(null)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full transition-all"
                            >
                                <X size={20} />
                            </button>
                        </div>
                        <div className="p-6 md:p-8 space-y-6">
                            <div>
                                <h2 className="text-2xl font-semibold text-slate-900 mb-3 leading-tight tracking-tight">{selectedEvent.title}</h2>
                                <span className={`text-[10px] font-semibold px-3 py-1.5 rounded-lg uppercase tracking-wider
                                    ${selectedEvent.type === 'Meeting' ? 'bg-purple-50 text-purple-600 border border-purple-100' :
                                        selectedEvent.type === 'Holiday' ? 'bg-sky-50 text-sky-600 border border-sky-100' :
                                            'bg-blue-50 text-blue-600 border border-blue-100'}`}>
                                    {selectedEvent.type}
                                </span>
                            </div>

                            <div className="flex items-center gap-4 text-slate-600 text-sm bg-slate-50/50 p-5 rounded-2xl border border-slate-100">
                                <div className="p-2.5 bg-white rounded-xl shadow-sm border border-slate-100 text-indigo-600">
                                    <Clock size={18} strokeWidth={2} />
                                </div>
                                <div className="min-w-0">
                                    <div className="font-semibold text-slate-900 uppercase text-[10px] tracking-widest truncate mb-0.5">
                                        {new Date(selectedEvent.start).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                                    </div>
                                    <div className="text-slate-500 font-medium text-xs">
                                        {new Date(selectedEvent.start).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} — {new Date(selectedEvent.end).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </div>
                                </div>
                            </div>

                            {selectedEvent.description && (
                                <div className="space-y-3">
                                    <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1">Description</h4>
                                    <div className="text-sm font-medium text-slate-600 bg-slate-50/50 p-5 rounded-2xl border border-slate-100 leading-relaxed whitespace-pre-wrap max-h-60 overflow-y-auto">
                                        {selectedEvent.description}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="p-6 bg-white border-t border-slate-50">
                            <button
                                onClick={() => setSelectedEvent(null)}
                                className="w-full py-3.5 bg-white border border-slate-200 rounded-xl text-xs font-semibold text-slate-600 uppercase tracking-widest hover:bg-slate-50 hover:border-slate-300 transition-all active:scale-[0.98] shadow-sm"
                            >
                                Close Details
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect, useCallback } from 'react';
import api from '../../services/api';
import { Plus, X, Calendar as CalendarIcon } from 'lucide-react';
import { useUI } from '../../context/UIContext';

export default function EmployeeLeave() {
    const { alert, toast } = useUI();
    const [leaves, setLeaves] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        type: 'Sick Leave',
        startDate: '',
        endDate: '',
        reason: ''
    });

    const fetchLeaves = useCallback(async () => {
        setLoading(true);
        try {
            const res = await api.get('/employee/dashboard/leaves');
            setLeaves(res.data);
        } catch (error) {
            console.error("Error fetching leaves", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchLeaves();
    }, [fetchLeaves]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await api.post('/employee/dashboard/leaves', formData);
            toast.success('Leave application submitted successfully!');
            setShowForm(false);
            setFormData({ type: 'Sick Leave', startDate: '', endDate: '', reason: '' });
            fetchLeaves(); // Refresh list
        } catch (error) {
            alert('Error', 'Failed to apply for leave', 'error');
        }
    };

    if (loading && !leaves.length) return (
        <div className="flex flex-col items-center justify-center min-h-[400px] space-y-4">
            <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-500 font-bold animate-pulse">Loading leave records...</p>
        </div>
    );

    return (
        <div className="space-y-8 animate-in fade-in duration-500 pb-20">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div className="flex flex-col gap-1.5">
                    <h1 className="text-2xl md:text-3xl font-bold text-slate-900 tracking-tight">Leave Management</h1>
                    <p className="text-sm font-semibold text-slate-400 uppercase tracking-widest">History & Applications</p>
                </div>
                <button
                    onClick={() => setShowForm(true)}
                    className="flex items-center justify-center gap-2.5 bg-blue-600 text-white px-6 py-4 rounded-2xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-200 font-bold text-sm uppercase tracking-widest w-full md:w-auto active:scale-[0.98]"
                >
                    <Plus size={20} /> Apply for New Leave
                </button>
            </div>

            {/* Apply Form Modal */}
            {showForm && (
                <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center bg-slate-900/60 backdrop-blur-md p-0 md:p-4">
                    <div className="w-full max-w-lg rounded-t-3xl md:rounded-2xl bg-white shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-full md:slide-in-from-bottom-4 duration-300">
                        <div className="flex justify-between items-center p-6 border-b border-slate-50 bg-slate-50/50">
                            <div>
                                <h3 className="text-lg md:text-xl font-bold text-slate-900">Apply for Leave</h3>
                                <p className="text-[10px] font-semibold text-slate-400 uppercase tracking-widest">Submit New Request</p>
                            </div>
                            <button onClick={() => setShowForm(false)} className="p-2 text-slate-400 hover:text-slate-600 hover:bg-white rounded-full transition-all">
                                <X size={24} />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-6">
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">Leave Type</label>
                                <select
                                    className="w-full rounded-xl border-2 border-slate-100 p-3.5 bg-slate-50 focus:bg-white focus:border-blue-500 outline-none transition-all font-semibold text-slate-700 appearance-none"
                                    value={formData.type}
                                    onChange={e => setFormData({ ...formData, type: e.target.value })}
                                >
                                    <option>Sick Leave</option>
                                    <option>Casual Leave</option>
                                    <option>Paid Leave</option>
                                    <option>Unpaid Leave</option>
                                </select>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">Start Date</label>
                                    <input
                                        type="date"
                                        required
                                        className="w-full rounded-xl border-2 border-slate-100 p-3.5 bg-slate-50 focus:bg-white focus:border-blue-500 outline-none transition-all font-semibold text-slate-700"
                                        value={formData.startDate}
                                        onChange={e => setFormData({ ...formData, startDate: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">End Date</label>
                                    <input
                                        type="date"
                                        required
                                        className="w-full rounded-xl border-2 border-slate-100 p-3.5 bg-slate-50 focus:bg-white focus:border-blue-500 outline-none transition-all font-semibold text-slate-700"
                                        value={formData.endDate}
                                        onChange={e => setFormData({ ...formData, endDate: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">Reason</label>
                                <textarea
                                    required
                                    className="w-full rounded-xl border-2 border-slate-100 p-4 bg-slate-50 focus:bg-white focus:border-blue-500 outline-none transition-all font-semibold text-slate-700 placeholder:text-slate-300 min-h-[120px]"
                                    placeholder="Briefly describe the reason for your leave..."
                                    value={formData.reason}
                                    onChange={e => setFormData({ ...formData, reason: e.target.value })}
                                />
                            </div>
                            <div className="flex gap-4 pt-4">
                                <button
                                    type="button"
                                    onClick={() => setShowForm(false)}
                                    className="flex-1 py-4 text-slate-500 hover:bg-slate-50 rounded-xl font-bold text-xs uppercase tracking-widest transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-[2] py-4 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-bold text-xs uppercase tracking-widest shadow-lg shadow-blue-200 transition-all active:scale-[0.98]"
                                >
                                    Submit Request
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <div className="space-y-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-[0.2em] mb-4">Past & Pending Requests</h3>
                {leaves.length === 0 ? (
                    <div className="text-center py-20 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
                        <CalendarIcon className="mx-auto text-slate-300 mb-2" size={40} />
                        <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">No leave requests found</p>
                    </div>
                ) : (
                    leaves.map(leave => (
                        <div key={leave._id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-lg shadow-slate-100/50 flex flex-col gap-5 transition-all active:scale-[0.99] hover:border-blue-100">
                            <div className="flex justify-between items-start">
                                <div className="space-y-1">
                                    <h4 className="font-bold text-slate-900 text-lg">{leave.type}</h4>
                                    <div className="flex items-center gap-2 text-slate-400">
                                        <CalendarIcon size={14} />
                                        <span className="text-xs font-semibold whitespace-nowrap">
                                            {new Date(leave.startDate).toLocaleDateString()} - {new Date(leave.endDate).toLocaleDateString()}
                                        </span>
                                    </div>
                                </div>
                                <span className={`text-[10px] px-3 py-1 rounded-xl font-bold uppercase tracking-widest
                                    ${leave.status === 'Approved' ? 'bg-emerald-100 text-emerald-700' :
                                        leave.status === 'Rejected' ? 'bg-red-100 text-red-700' :
                                            'bg-amber-100 text-amber-700'}`}>
                                    {leave.status}
                                </span>
                            </div>

                            <div className="bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Reason</p>
                                <p className="text-sm font-semibold text-slate-600 leading-relaxed italic">"{leave.reason}"</p>
                            </div>

                            <div className="flex justify-between items-center text-[10px] font-bold text-slate-300 uppercase tracking-widest">
                                <span>Applied On</span>
                                <span>{new Date(leave.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Download, FileText, Database, Clock, CheckCircle, AlertCircle, Loader2, Users, Building2, IndianRupee, Receipt } from 'lucide-react';
import api from '../../services/api';
import toast from 'react-hot-toast';
import html2pdf from 'html2pdf.js';
import { useSearchParams } from 'react-router-dom';
import { useUI } from '../../context/UIContext';

export default function BackupAndReports() {
    const { confirm } = useUI();
    const [searchParams] = useSearchParams();
    const queryCompanyId = searchParams.get('companyId');

    const [backups, setBackups] = useState([]);
    const [loading, setLoading] = useState(true);
    const [creating, setCreating] = useState(false);
    const [companies, setCompanies] = useState([]);
    const [selectedCompanyId, setSelectedCompanyId] = useState(queryCompanyId || localStorage.getItem('companyId') || '');
    const [isSuperAdmin, setIsSuperAdmin] = useState(false);
    const [filters, setFilters] = useState({
        dateRange: 'all',
        includeFiles: true,
        includePII: false,
        modules: []
    });
    const [companyConfig, setCompanyConfig] = useState(null);

    useEffect(() => {
        const user = JSON.parse(localStorage.getItem('user') || '{}');
        const sa = user.role === 'SUPER_ADMIN' || user.isSuperAdmin;
        setIsSuperAdmin(sa);

        if (sa) {
            fetchCompanies();
        }

        if (selectedCompanyId) {
            fetchBackups();
            fetchConfig();
        } else {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedCompanyId]);

    const fetchCompanies = async () => {
        try {
            const res = await api.get('/sa/companies', { params: { limit: 100 } });
            setCompanies(res.data.companies || []);
        } catch (e) {
            console.error("Failed to fetch companies");
        }
    };



    // Polling for active backups
    useEffect(() => {
        const hasActive = backups.some(b => b.status === 'QUEUED' || b.status === 'PROCESSING');
        if (hasActive) {
            const interval = setInterval(fetchBackups, 5000);
            return () => clearInterval(interval);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [backups]);

    const fetchConfig = async () => {
        if (!selectedCompanyId) return;
        try {
            const res = await api.get('/company/config', { headers: { 'x-company-id': selectedCompanyId } });
            setCompanyConfig(res.data.company);
        } catch (e) {
            console.error("Failed to load company config");
        }
    };

    const fetchBackups = async () => {
        if (!selectedCompanyId) return;
        try {
            const res = await api.get('/backups', { headers: { 'x-company-id': selectedCompanyId } });
            setBackups(res.data);
        } catch (error) {
            console.error("Failed to fetch backups", error);
        } finally {
            setLoading(false);
        }
    };

    const handleCreateBackup = async () => {
        if (!selectedCompanyId) return toast.error("Please select a company first");
        try {
            setCreating(true);
            const res = await api.post('/backups', { filters }, { headers: { 'x-company-id': selectedCompanyId } });
            setBackups([res.data, ...backups]);
            toast.success("Backup job started!");
        } catch (error) {
            toast.error("Failed to start backup");
        } finally {
            setCreating(false);
        }
    };

    const handleDownload = async (id, fileName) => {
        if (!selectedCompanyId) return;
        try {
            toast.loading("Preparing download...");
            const response = await api.get(`/backups/${id}/download`, {
                headers: { 'x-company-id': selectedCompanyId },
                responseType: 'blob'
            });

            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', fileName || `backup_${id}.zip`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
            toast.dismiss();
            toast.success("Download started");
        } catch (error) {
            console.error("Download failed", error);
            toast.dismiss();
            toast.error("Download failed. Your session might have expired.");
        }
    };

    const handleDelete = async (id) => {
        const ok = await confirm('Delete Backup', "Are you sure you want to delete this backup?", 'Delete');
        if (!ok) return;
        try {
            await api.delete(`/backups/${id}`, { headers: { 'x-company-id': selectedCompanyId } });
            setBackups(backups.filter(b => b._id !== id));
            toast.success("Backup deleted");
        } catch (error) {
            toast.error("Failed to delete backup");
        }
    };

    // --- QUICK REPORTS LOGIC (Migrated) ---

    const generateFinanceReport = async () => {
        if (!selectedCompanyId) return toast.error("Select a company first");
        try {
            toast.loading("Generating Finance Report...");
            const [invoiceRes, expenseRes] = await Promise.all([
                api.get('/invoices', { params: { companyId: selectedCompanyId } }),
                api.get('/expenses', { params: { companyId: selectedCompanyId } })
            ]);
            // ... (rest of function unchanged, just uses locally fetched data)
            const expenses = expenseRes.data;
            const invoices = invoiceRes.data;

            const element = document.createElement('div');
            element.style.padding = '20px';
            element.innerHTML = `
                <div style="font-family: sans-serif;">
                    <h1 style="text-align: center;">Financial Report - ${companyConfig?.name || 'YVO Company'}</h1>
                    <p style="text-align: center; color: #666;">Generated on ${new Date().toLocaleDateString()}</p>
                    <hr/>
                    <h3>Summary</h3>
                    <p>Total Revenue: ₹${invoices.filter(i => i.status === 'PAID').reduce((s, i) => s + (i.grandTotal || 0), 0)}</p>
                    <p>Total Expenses: ₹${expenses.reduce((s, e) => s + (e.amount || 0), 0)}</p>
                    <hr/>
                    <h3>Expenses</h3>
                    <table style="width: 100%; border-collapse: collapse;">
                        <tr style="background: #eee;">
                            <th style="border: 1px solid #ddd; padding: 8px;">Date</th>
                            <th style="border: 1px solid #ddd; padding: 8px;">Category</th>
                            <th style="border: 1px solid #ddd; padding: 8px;">Amount</th>
                        </tr>
                        ${expenses.map(e => `
                            <tr>
                                <td style="border: 1px solid #ddd; padding: 8px;">${new Date(e.date).toLocaleDateString()}</td>
                                <td style="border: 1px solid #ddd; padding: 8px;">${e.category}</td>
                                <td style="border: 1px solid #ddd; padding: 8px;">₹${e.amount}</td>
                            </tr>
                        `).join('')}
                    </table>
                </div>
            `;

            html2pdf().from(element).save(`Finance_Report_${new Date().toISOString().split('T')[0]}.pdf`);
            toast.dismiss();
            toast.success("Finance report downloaded");
        } catch (e) {
            toast.dismiss();
            toast.error("Failed to generate report");
        }
    };

    const downloadCSVReport = async (type) => {
        if (!selectedCompanyId) return toast.error("Select a company first");
        try {
            toast.loading(`Generating ${type} report...`);
            let data = [];
            let filename = `report_${type}_${new Date().toISOString().split('T')[0]}.csv`;

            if (type === 'payroll') {
                const res = await api.get('/employees', { params: { companyId: selectedCompanyId } });
                data = res.data.map(emp => ({ Name: `${emp.firstName} ${emp.lastName}`, Position: emp.position, Salary: emp.salary }));
            } else if (type === 'revenue') {
                const res = await api.get('/invoices', { params: { companyId: selectedCompanyId } });
                data = res.data.filter(i => i.status === 'PAID').map(i => ({ Invoice: i.invoiceNumber, Client: i.customerName, Amount: i.grandTotal, Date: i.date }));
            }

            if (!data.length) {
                toast.dismiss();
                toast.error("No data available");
                return;
            }

            const headers = Object.keys(data[0]);
            const csvContent = [headers.join(','), ...data.map(row => headers.map(h => `"${String(row[h] || '').replace(/"/g, '""')}"`).join(','))].join('\n');
            const blob = new Blob([csvContent], { type: 'text/csv' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = filename;
            link.click();

            toast.dismiss();
            toast.success(`${type} report downloaded`);
        } catch (e) {
            toast.dismiss();
            toast.error("Failed to generate CSV");
        }
    };

    return (
        <div className="space-y-8 p-6 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800">Backup & Reports</h1>
                    <p className="text-slate-500 mt-2">Manage your company data exports and financial reports from one central location.</p>
                </div>

                {isSuperAdmin && (
                    <div className="w-full md:w-64 bg-white p-4 rounded-xl border border-blue-100 shadow-sm flex flex-col gap-2">
                        <label className="text-[10px] font-bold text-blue-600 uppercase tracking-wider">Select Company Context</label>
                        <select
                            className="bg-slate-50 border border-slate-200 text-sm rounded-lg p-2 outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                            value={selectedCompanyId}
                            onChange={(e) => setSelectedCompanyId(e.target.value)}
                        >
                            <option value="">-- Select Company --</option>
                            {companies.map(c => (
                                <option key={c._id} value={c._id}>{c.name}</option>
                            ))}
                        </select>
                    </div>
                )}
            </div>

            {!selectedCompanyId && isSuperAdmin ? (
                <div className="bg-white rounded-2xl border-2 border-dashed border-slate-200 p-12 text-center flex flex-col items-center justify-center">
                    <div className="p-4 bg-blue-50 text-blue-500 rounded-full mb-4">
                        <Building2 size={40} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-700">Please Select a Company</h3>
                    <p className="text-slate-500 max-w-sm mt-2">Select a company from the dropdown at the top right to manage its backups and reports.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Left Column: Backup Configuration */}
                    <div className="lg:col-span-1 space-y-6">
                        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                            <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                                <Database size={20} className="text-indigo-600" /> New Backup
                            </h2>

                            <div className="space-y-4">
                                <div>
                                    <label className="text-sm font-semibold text-slate-700 block mb-2">Date Range</label>
                                    <select
                                        className="w-full bg-slate-50 border border-slate-200 rounded-lg p-3 text-sm"
                                        value={filters.dateRange}
                                        onChange={e => setFilters({ ...filters, dateRange: e.target.value })}
                                    >
                                        <option value="all">Full Export (All Time)</option>
                                        <option value="last_7">Last 7 Days</option>
                                        <option value="last_30">Last 30 Days</option>
                                        <option value="last_90">Last 90 Days</option>
                                    </select>
                                </div>

                                <div className="space-y-3">
                                    <label className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-not-allowed opacity-70">
                                        <input type="checkbox" checked={true} readOnly className="rounded text-indigo-600" />
                                        <span className="text-sm font-medium text-slate-700">Database Records (.json, .csv)</span>
                                    </label>
                                    <label className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition">
                                        <input
                                            type="checkbox"
                                            checked={filters.includeFiles}
                                            onChange={e => setFilters({ ...filters, includeFiles: e.target.checked })}
                                            className="rounded text-indigo-600 focus:ring-indigo-500"
                                        />
                                        <span className="text-sm font-medium text-slate-700">Include Uploaded Files</span>
                                    </label>
                                    <label className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition">
                                        <input
                                            type="checkbox"
                                            checked={filters.includePII}
                                            onChange={e => setFilters({ ...filters, includePII: e.target.checked })}
                                            className="rounded text-indigo-600 focus:ring-indigo-500"
                                        />
                                        <div className="flex flex-col">
                                            <span className="text-sm font-medium text-slate-700">Include Personal Data (PII)</span>
                                            <span className="text-[10px] text-slate-400">Emails, Phone Numbers (unmasked)</span>
                                        </div>
                                    </label>
                                </div>

                                <button
                                    onClick={handleCreateBackup}
                                    disabled={creating}
                                    className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 flex items-center justify-center gap-3 disabled:opacity-50 mt-4"
                                >
                                    {creating ? <Loader2 size={20} className="animate-spin" /> : <Download size={20} />}
                                    Generate Full Backup
                                </button>
                                <p className="text-[11px] text-center text-slate-400">Backups are stored for 7 days before expiring.</p>
                            </div>
                        </div>

                        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-6 rounded-2xl text-white shadow-xl shadow-indigo-200">
                            <h3 className="font-bold text-lg mb-2">Quick Reports</h3>
                            <p className="text-indigo-100 text-sm mb-6">Instantly download specific summaries.</p>
                            <div className="space-y-3">
                                <ReportAction icon={<Receipt size={18} />} label="Finance Report (PDF)" onClick={generateFinanceReport} />
                                <ReportAction icon={<Users size={18} />} label="Payroll Export (CSV)" onClick={() => downloadCSVReport('payroll')} />
                                <ReportAction icon={<IndianRupee size={18} />} label="Revenue Export (CSV)" onClick={() => downloadCSVReport('revenue')} />
                            </div>
                        </div>
                    </div>

                    {/* Right Column: Backup History */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden min-h-[500px]">
                            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                                <h2 className="text-xl font-bold text-slate-800">Backup History</h2>
                                <button onClick={fetchBackups} className="p-2 text-slate-400 hover:text-indigo-600 transition">
                                    <Clock size={20} />
                                </button>
                            </div>

                            {loading ? (
                                <div className="flex flex-col items-center justify-center h-[400px] text-slate-400">
                                    <Loader2 size={40} className="animate-spin mb-4" />
                                    <span>Loading your backups...</span>
                                </div>
                            ) : backups.length > 0 ? (
                                <div className="divide-y divide-slate-100">
                                    {backups.map((bk) => (
                                        <BackupRow
                                            key={bk._id}
                                            backup={bk}
                                            onDownload={() => handleDownload(bk._id, `backup_${bk.backupId}.zip`)}
                                            onDelete={() => handleDelete(bk._id)}
                                        />
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center h-[400px] text-center p-10">
                                    <div className="p-6 bg-slate-50 rounded-full mb-4">
                                        <Database size={40} className="text-slate-300" />
                                    </div>
                                    <h3 className="text-lg font-bold text-slate-700">No backups yet</h3>
                                    <p className="text-slate-400 text-sm max-w-xs mt-2">Generate your first company backup to see it listed here.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}


const ReportAction = ({ icon, label, onClick }) => (
    <button
        onClick={onClick}
        className="w-full flex items-center gap-3 p-3 bg-white/10 hover:bg-white/20 rounded-xl transition text-sm font-medium border border-white/10"
    >
        {icon}
        <span>{label}</span>
    </button>
);

const BackupRow = ({ backup, onDownload, onDelete }) => {
    const statusIcons = {
        QUEUED: <Clock size={16} className="text-amber-500" />,
        PROCESSING: <Loader2 size={16} className="text-indigo-500 animate-spin" />,
        READY: <CheckCircle size={16} className="text-green-500" />,
        FAILED: <AlertCircle size={16} className="text-red-500" />,
        EXPIRED: <AlertCircle size={16} className="text-slate-400" />
    };

    return (
        <div className="p-6 hover:bg-slate-50/50 transition group">
            <div className="flex items-start justify-between gap-4">
                <div className="flex items-start gap-4">
                    <div className={`p-3 rounded-xl ${backup.status === 'READY' ? 'bg-green-50 text-green-600' : 'bg-slate-100 text-slate-400'}`}>
                        <FileText size={20} />
                    </div>
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <span className="font-bold text-slate-800">{backup.backupId}</span>
                            <span className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${backup.status === 'READY' ? 'bg-green-100 text-green-700' :
                                backup.status === 'FAILED' ? 'bg-red-100 text-red-700' :
                                    'bg-slate-100 text-slate-500'
                                }`}>
                                {statusIcons[backup.status]}
                                {backup.status}
                            </span>
                        </div>
                        <div className="text-xs text-slate-400 flex items-center gap-3">
                            <span>{new Date(backup.createdAt).toLocaleString()}</span>
                            {backup.fileSize && <span>• {(backup.fileSize / (1024 * 1024)).toFixed(2)} MB</span>}
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    {backup.status === 'READY' && (
                        <button
                            onClick={onDownload}
                            className="p-2.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition shadow-sm"
                            title="Download ZIP"
                        >
                            <Download size={18} />
                        </button>
                    )}
                    <button
                        onClick={onDelete}
                        className="p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition"
                        title="Delete Backup"
                    >
                        <AlertCircle size={18} />
                    </button>
                </div>
            </div>

            {backup.status === 'PROCESSING' && (
                <div className="mt-4">
                    <div className="flex justify-between text-[10px] text-slate-500 mb-1 font-medium">
                        <span>Processing {backup.currentModule || 'data'}...</span>
                        <span>{backup.progress}%</span>
                    </div>
                    <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                        <div className="bg-indigo-500 h-full transition-all duration-500" style={{ width: `${backup.progress}%` }}></div>
                    </div>
                </div>
            )}

            {backup.status === 'FAILED' && backup.error && (
                <div className="mt-2 text-xs text-red-500 bg-red-50 p-2 rounded-lg border border-red-100">
                    Error: {backup.error}
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { MessageSquare, Users, Send, Trash2, UserPlus, X } from 'lucide-react';
import api from '../../services/api';
import { toast } from 'react-hot-toast';
import { useUI } from '../../context/UIContext';

export default function Broadcasts() {
    const { confirm } = useUI();
    const [subTab, setSubTab] = useState('compose');
    const [allEmployees, setAllEmployees] = useState([]);
    const companyId = localStorage.getItem('companyId');

    // Modal & Selection States
    const [showCreateGroup, setShowCreateGroup] = useState(false);
    const [groups, setGroups] = useState([]);
    const [selectedGroup, setSelectedGroup] = useState(null);
    const [newGroupName, setNewGroupName] = useState('');
    const [selectedEmployeeId, setSelectedEmployeeId] = useState('');

    // Message Composition State
    const [messageContent, setMessageContent] = useState('');
    const [recipientId, setRecipientId] = useState('all'); // 'all' or groupId

    const fetchGroups = async () => {
        try {
            const { data } = await api.get(`/employees/groups?companyId=${companyId}`);
            setGroups(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error("Failed to fetch groups", error);
            toast.error('Failed to load groups');
        }
    };

    const fetchEmployees = async () => {
        try {
            const { data } = await api.get(`/employees?companyId=${companyId}`);
            if (Array.isArray(data)) {
                setAllEmployees(data.map(e => ({
                    id: e._id,
                    name: `${e.firstName} ${e.lastName}`,
                    firstName: e.firstName,
                    lastName: e.lastName,
                })));
            }
        } catch (error) {
            console.error("Failed to fetch employees", error);
        }
    };

    useEffect(() => {
        if (companyId) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            fetchGroups();
            // eslint-disable-next-line react-hooks/set-state-in-effect
            fetchEmployees();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [companyId]);

    const handleCreateGroup = async (e) => {
        e.preventDefault();
        if (!newGroupName.trim()) return;

        try {
            const { data } = await api.post('/employees/groups', {
                companyId,
                name: newGroupName,
                members: []
            });
            setGroups(prev => [data, ...prev]);
            setNewGroupName('');
            setShowCreateGroup(false);
            toast.success('Group created successfully');
        } catch (error) {
            console.error(error);
            toast.error('Failed to create group');
        }
    };

    const handleDeleteGroup = async (groupId) => {
        const ok = await confirm('Delete Group', 'Are you sure you want to delete this group? This action cannot be undone.', 'Delete');
        if (!ok) return;

        try {
            await api.delete(`/employees/groups/${groupId}`);
            setGroups(prev => prev.filter(g => g._id !== groupId));
            if (selectedGroup?._id === groupId) setSelectedGroup(null);
            toast.success('Group deleted');
        } catch (error) {
            console.error(error);
            toast.error('Failed to delete group');
        }
    };

    const handleAddMember = async () => {
        if (!selectedEmployeeId || !selectedGroup) return;

        const currentMembers = selectedGroup.members || [];
        if (currentMembers.some(m => m._id === selectedEmployeeId)) {
            toast.error('Member already in group');
            return;
        }

        const employee = allEmployees.find(e => e.id === selectedEmployeeId);
        if (!employee) return;

        // Optimistic update for UI responsiveness
        const newMember = { _id: employee.id, firstName: employee.firstName, lastName: employee.lastName };
        const updatedGroupOptimistic = {
            ...selectedGroup,
            members: [...currentMembers, newMember]
        };
        setSelectedGroup(updatedGroupOptimistic);

        try {
            const updatedMemberIds = updatedGroupOptimistic.members.map(m => m._id);
            const { data } = await api.put(`/employees/groups/${selectedGroup._id}`, {
                name: selectedGroup.name,
                members: updatedMemberIds
            });

            // Sync with server response
            setGroups(prev => prev.map(g => g._id === selectedGroup._id ? data : g));
            setSelectedGroup(data);
            setSelectedEmployeeId('');
            toast.success('Member added');
        } catch (error) {
            console.error(error);
            toast.error('Failed to add member');
            // Revert on failure
            fetchGroups();
            if (selectedGroup) {
                const originalGroup = groups.find(g => g._id === selectedGroup._id);
                if (originalGroup) setSelectedGroup(originalGroup);
            }
        }
    };

    const handleRemoveMember = async (memberId) => {
        if (!selectedGroup) return;

        const ok = await confirm('Remove Member', 'Remove this member?', 'Remove');
        if (!ok) return;

        const currentMembers = selectedGroup.members || [];
        const updatedMembers = currentMembers.filter(m => m._id !== memberId);

        // Optimistic update
        const updatedGroupOptimistic = { ...selectedGroup, members: updatedMembers };
        setSelectedGroup(updatedGroupOptimistic);

        try {
            const updatedMemberIds = updatedMembers.map(m => m._id);
            const { data } = await api.put(`/employees/groups/${selectedGroup._id}`, {
                name: selectedGroup.name,
                members: updatedMemberIds
            });

            setGroups(prev => prev.map(g => g._id === selectedGroup._id ? data : g));
            setSelectedGroup(data);
            toast.success('Member removed');
        } catch (error) {
            console.error(error);
            toast.error('Failed to remove member');
            fetchGroups(); // Revert
        }
    };

    const handleSendMessage = async () => {
        if (!messageContent.trim()) {
            toast.error('Please enter a message');
            return;
        }

        const storedUser = localStorage.getItem('user');
        const user = storedUser ? JSON.parse(storedUser) : null;
        const senderId = user?._id || user?.id;

        if (!senderId) {
            toast.error('User not authenticated properly');
            return;
        }

        try {
            await api.post('/employees/send-message', {
                companyId,
                senderId,
                groupId: recipientId === 'all' ? null : recipientId,
                targetAll: recipientId === 'all',
                content: messageContent,
                attachments: []
            });
            setMessageContent('');
            setRecipientId('all');
            toast.success('Broadcast sent successfully');
        } catch (error) {
            console.error('Failed to send message:', error);
            toast.error('Failed to send broadcast');
        }
    };

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-slate-800">Broadcast Center</h1>

            {/* Navigation Tabs */}
            <div className="flex gap-6 border-b border-slate-200">
                <button
                    onClick={() => setSubTab('compose')}
                    className={`pb-3 text-sm font-medium transition-colors ${subTab === 'compose' ? 'border-b-2 border-blue-600 text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Compose Message
                </button>
                <button
                    onClick={() => setSubTab('groups')}
                    className={`pb-3 text-sm font-medium transition-colors ${subTab === 'groups' ? 'border-b-2 border-blue-600 text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Manage Groups
                </button>
            </div>

            {/* Compose Message Tab */}
            {subTab === 'compose' && (
                <div className="max-w-3xl bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
                    <h3 className="text-lg font-semibold text-slate-800 mb-6 flex items-center gap-2">
                        <MessageSquare size={20} className="text-blue-600" />
                        Send Broadcast
                    </h3>
                    <form className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Recipient Group</label>
                            <select
                                value={recipientId}
                                onChange={(e) => setRecipientId(e.target.value)}
                                className="w-full rounded-lg border border-slate-300 p-3 bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                            >
                                <option value="all">All Employees</option>
                                {groups.map(g => (
                                    <option key={g._id} value={g._id}>{g.name} ({g.members?.length || 0} members)</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Message Content</label>
                            <textarea
                                value={messageContent}
                                onChange={(e) => setMessageContent(e.target.value)}
                                className="w-full rounded-lg border border-slate-300 p-4 h-40 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all resize-none"
                                placeholder="Type your message here..."
                            ></textarea>
                        </div>
                        <div className="flex justify-end pt-2">
                            <button
                                type="button"
                                onClick={handleSendMessage}
                                className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2.5 rounded-lg hover:bg-blue-700 transition-colors shadow-sm font-medium"
                            >
                                <Send size={18} /> Send Broadcast
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* Manage Groups Tab */}
            {subTab === 'groups' && (
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm min-h-[500px]">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                            <Users size={20} className="text-blue-600" />
                            Employee Groups
                        </h3>
                        <button
                            onClick={() => setShowCreateGroup(true)}
                            className="text-sm bg-blue-50 text-blue-600 px-4 py-2 rounded-lg hover:bg-blue-100 transition-colors font-medium flex items-center gap-2"
                        >
                            + Create New Group
                        </button>
                    </div>

                    {/* Inline Create Group Form */}
                    {showCreateGroup && (
                        <div className="mb-6 p-5 bg-slate-50 rounded-xl border border-slate-200 animate-in fade-in slide-in-from-top-2">
                            <h4 className="text-sm font-semibold text-slate-700 mb-3">Create New Group</h4>
                            <form onSubmit={handleCreateGroup} className="flex gap-3">
                                <input
                                    type="text"
                                    value={newGroupName}
                                    onChange={(e) => setNewGroupName(e.target.value)}
                                    placeholder="Enter group name (e.g. Marketing Team)"
                                    className="flex-1 rounded-lg border border-slate-300 px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    autoFocus
                                />
                                <button
                                    type="submit"
                                    className="bg-blue-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
                                >
                                    Create
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setShowCreateGroup(false)}
                                    className="bg-white text-slate-600 px-5 py-2.5 rounded-lg text-sm font-medium border border-slate-300 hover:bg-slate-50 transition-colors"
                                >
                                    Cancel
                                </button>
                            </form>
                        </div>
                    )}

                    {/* Groups Grid */}
                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                        {groups.map(g => (
                            <div
                                key={g._id}
                                onClick={() => setSelectedGroup(g)}
                                className="group relative p-5 border border-slate-200 rounded-xl hover:border-blue-300 hover:shadow-md transition-all cursor-pointer bg-white"
                            >
                                <div className="flex justify-between items-start mb-2">
                                    <h4 className="font-semibold text-slate-800 text-lg">{g.name}</h4>
                                    <span className="bg-slate-100 text-slate-600 text-xs px-2 py-1 rounded-full font-medium">
                                        {g.members?.length || 0}
                                    </span>
                                </div>
                                <p className="text-sm text-slate-500 line-clamp-1">
                                    {(g.members && g.members.length > 0)
                                        ? g.members.map(m => m.firstName).join(', ')
                                        : "No members yet"}
                                </p>
                            </div>
                        ))}
                        {groups.length === 0 && (
                            <div className="col-span-full py-12 text-center text-slate-400">
                                <Users size={48} className="mx-auto mb-3 opacity-20" />
                                <p>No groups found. Create one to get started.</p>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Manage Members Modal */}
            {selectedGroup && (
                <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in fade-in duration-200">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[85vh]">
                        {/* Modal Header */}
                        <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                            <div>
                                <h3 className="font-bold text-lg text-slate-800">{selectedGroup.name}</h3>
                                <p className="text-xs text-slate-500 mt-0.5">Manage group members</p>
                            </div>
                            <button
                                onClick={() => setSelectedGroup(null)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200 rounded-full transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>

                        {/* Modal Body */}
                        <div className="p-6 flex-1 overflow-y-auto">
                            {/* Add Member Section */}
                            <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100 mb-6">
                                <label className="block text-xs font-bold text-blue-800 uppercase tracking-wide mb-2">Add New Member</label>
                                <div className="flex gap-2">
                                    <select
                                        value={selectedEmployeeId}
                                        onChange={(e) => setSelectedEmployeeId(e.target.value)}
                                        className="flex-1 rounded-lg border border-slate-300 text-sm p-2.5 focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                                    >
                                        <option value="">Select Employee...</option>
                                        {allEmployees
                                            .filter(e => !selectedGroup.members?.some(m => m._id === e.id))
                                            .map(e => (
                                                <option key={e.id} value={e.id}>{e.name}</option>
                                            ))
                                        }
                                    </select>
                                    <button
                                        onClick={handleAddMember}
                                        disabled={!selectedEmployeeId}
                                        className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                    >
                                        Add
                                    </button>
                                </div>
                            </div>

                            {/* Members List */}
                            <div>
                                <h4 className="text-sm font-semibold text-slate-700 mb-3 flex items-center justify-between">
                                    Current Members
                                    <span className="text-xs font-normal text-slate-500 bg-slate-100 px-2 py-0.5 rounded-full">
                                        {selectedGroup.members?.length || 0}
                                    </span>
                                </h4>
                                <div className="space-y-2">
                                    {(!selectedGroup.members || selectedGroup.members.length === 0) ? (
                                        <div className="text-sm text-slate-400 italic py-8 text-center border-2 border-dashed border-slate-100 rounded-xl">
                                            No members in this group yet.
                                        </div>
                                    ) : (
                                        selectedGroup.members.map(m => (
                                            <div key={m._id} className="flex justify-between items-center p-3 hover:bg-slate-50 rounded-lg border border-transparent hover:border-slate-100 transition-colors group">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 text-xs font-bold">
                                                        {m.firstName?.[0]}{m.lastName?.[0]}
                                                    </div>
                                                    <span className="text-sm font-medium text-slate-700">{m.firstName} {m.lastName}</span>
                                                </div>
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); handleRemoveMember(m._id); }}
                                                    className="text-red-500 opacity-0 group-hover:opacity-100 hover:text-red-700 p-2 hover:bg-red-50 rounded-lg transition-all"
                                                    title="Remove Member"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        </div>

                        {/* Modal Footer */}
                        <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                            <button
                                onClick={() => handleDeleteGroup(selectedGroup._id)}
                                className="text-red-600 text-sm hover:text-red-700 font-medium hover:underline px-2"
                            >
                                Delete Group
                            </button>
                            <button
                                onClick={() => setSelectedGroup(null)}
                                className="bg-white border border-slate-300 text-slate-700 px-5 py-2 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors shadow-sm"
                            >
                                Close
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useOutletContext, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import toast from 'react-hot-toast';
import { Plus, Search, User, Phone, FileText, IndianRupee, Eye, X, Trash2, Trash, RotateCcw, Edit2 } from 'lucide-react';
import { useUI } from '../../context/UIContext';

export default function Customers() {
    const navigate = useNavigate();
    const [customers, setCustomers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isViewDeleted] = useState(false);
    const [isEditing] = useState(false);

    // Payment Modal State
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [selectedCustomerForPayment, setSelectedCustomerForPayment] = useState(null);
    const [paymentData, setPaymentData] = useState({
        amount: '',
        date: new Date().toISOString().slice(0, 10),
        method: 'CASH'
    });

    const [formData, setFormData] = useState({
        name: '',
        phone: '',
        address: '',
        email: '',
        taxId: ''
    });

    const fetchCustomers = async () => {
        try {
            setLoading(true);
            const companyId = localStorage.getItem('companyId');
            if (!companyId) return;
            const res = await api.get(`/customers`, { params: { companyId, isDeleted: isViewDeleted } });
            setCustomers(res.data);
        } catch (err) {
            toast.error('Failed to load customers');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchCustomers();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const handleCreateCustomer = async (e) => {
        e.preventDefault();
        try {
            await api.post('/customers', {
                companyId: localStorage.getItem('companyId'),
                ...formData
            });
            toast.success('Customer created successfully');
            setIsAddModalOpen(false);
            setFormData({ name: '', phone: '', address: '', email: '', taxId: '' });
            fetchCustomers();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to create customer');
        }
    };

    const handleReceivePayment = async (e) => {
        e.preventDefault();
        try {
            const companyId = localStorage.getItem('companyId');
            if (!companyId) throw new Error('Company ID not found');

            await api.post('/client-payments', {
                companyId: companyId,
                customerId: selectedCustomerForPayment.id || selectedCustomerForPayment._id,
                amount: parseFloat(paymentData.amount),
                date: paymentData.date,
                method: paymentData.method
            });
            toast.success('Payment recorded successfully');
            setIsPaymentModalOpen(false);
            setPaymentData({ amount: '', date: new Date().toISOString().slice(0, 10), method: 'CASH' });
            fetchCustomers(); // Refresh the customer list to show new due balances
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to record payment');
        }
    };

    const filteredCustomers = customers.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (c.phone && c.phone.includes(searchTerm))
    );

    if (loading) return <div className="p-8"><div className="animate-pulse flex space-x-4">Loading customers...</div></div>;

    return (
        <div className="max-w-7xl mx-auto space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">Customers</h1>
                    <p className="text-sm text-slate-500 mt-1">Manage your clients and their financial ledgers</p>
                </div>
                <div className="flex items-center gap-3 w-full md:w-auto">
                    <div className="relative flex-grow md:w-64">
                        <input
                            type="text"
                            placeholder="Search by name or phone..."
                            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        <Search size={18} className="absolute left-3 top-2.5 text-slate-400" />
                    </div>
                    <button
                        onClick={() => setIsAddModalOpen(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition"
                    >
                        <Plus size={18} />
                        <span className="hidden sm:inline">Add Customer</span>
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-slate-600">
                        <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-semibold border-b border-slate-200">
                            <tr>
                                <th className="px-6 py-4">Customer Details</th>
                                <th className="px-6 py-4 text-right hidden md:table-cell">Total Invoiced</th>
                                <th className="px-6 py-4 text-right hidden sm:table-cell">Total Received</th>
                                <th className="px-6 py-4 text-right">Total Due</th>
                                <th className="px-6 py-4 text-center">Action</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {filteredCustomers.length === 0 ? (
                                <tr>
                                    <td colSpan="5" className="px-6 py-8 text-center text-slate-500">
                                        <User size={48} className="mx-auto text-slate-300 mb-2" />
                                        <p>No customers found.</p>
                                    </td>
                                </tr>
                            ) : (
                                filteredCustomers.map((customer) => (
                                    <tr key={customer.id || customer._id} className="hover:bg-slate-50 transition cursor-pointer" onClick={() => navigate(`/dashboard/customers/${customer.id || customer._id}`)}>
                                        <td className="px-6 py-4">
                                            <div className="font-semibold text-slate-900">{customer.name}</div>
                                            <div className="text-xs text-slate-500 flex items-center mt-1">
                                                <Phone size={12} className="mr-1" /> {customer.phone || 'N/A'}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right font-medium hidden md:table-cell">
                                            ₹{(customer.totalInvoiced || 0).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-right font-medium text-green-600 hidden sm:table-cell">
                                            ₹{(customer.totalReceived || 0).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <span className={`px-2 py-1 rounded inline-flex font-bold ${(customer.totalDue || 0) > 0 ? 'bg-red-50 text-red-700' : 'text-slate-700'
                                                }`}>
                                                ₹{(customer.totalDue || 0).toLocaleString()}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <div className="flex items-center justify-center gap-2">
                                                <button
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        setSelectedCustomerForPayment(customer);
                                                        setIsPaymentModalOpen(true);
                                                    }}
                                                    className="px-3 py-1 text-xs font-bold text-green-700 bg-green-100 hover:bg-green-200 rounded transition whitespace-nowrap"
                                                    title="Receive Payment"
                                                >
                                                    Receive Payment
                                                </button>
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); navigate(`/dashboard/customers/${customer.id || customer._id}`); }}
                                                    className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition"
                                                    title="View Ledger"
                                                >
                                                    <Eye size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add Customer Modal */}
            {isAddModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsAddModalOpen(false)}></div>
                    <div className="relative w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden">
                        <div className="flex items-center justify-between p-5 border-b border-slate-200">
                            <h3 className="text-lg font-bold text-slate-800">{isEditing ? 'Edit Customer' : 'Add New Customer'}</h3>
                            <button onClick={() => setIsAddModalOpen(false)} className="p-1 hover:bg-slate-100 rounded-lg"><X size={20} /></button>
                        </div>
                        <form onSubmit={handleCreateCustomer} className="p-5 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Customer Name *</label>
                                <input type="text" required className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Phone Number *</label>
                                <input type="tel" required className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email <span className="text-slate-400 font-normal">(optional)</span></label>
                                <input type="email" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Address <span className="text-slate-400 font-normal">(optional)</span></label>
                                <textarea className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500" rows="2" value={formData.address} onChange={(e) => setFormData({ ...formData, address: e.target.value })}></textarea>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Tax ID / GST <span className="text-slate-400 font-normal">(optional)</span></label>
                                <input type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500" value={formData.taxId} onChange={(e) => setFormData({ ...formData, taxId: e.target.value })} />
                            </div>
                            <div className="pt-4 flex justify-end gap-3 border-t">
                                <button type="button" onClick={() => setIsAddModalOpen(false)} className="px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-100 rounded-lg">Cancel</button>
                                <button type="submit" className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium rounded-lg">Save Customer</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Receive Payment Modal */}
            {isPaymentModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsPaymentModalOpen(false)}></div>
                    <div className="relative w-full max-w-sm bg-white rounded-2xl shadow-2xl overflow-hidden">
                        <div className="flex items-center justify-between p-5 border-b border-slate-200">
                            <h3 className="text-lg font-bold text-slate-800">Receive Payment: {selectedCustomerForPayment?.name}</h3>
                            <button onClick={() => setIsPaymentModalOpen(false)} className="p-1 hover:bg-slate-100 rounded-lg"><X size={20} /></button>
                        </div>
                        <form onSubmit={handleReceivePayment} className="p-5 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Amount (₹) *</label>
                                <input type="number" required min="1" step="0.01" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500" value={paymentData.amount} onChange={(e) => setPaymentData({ ...paymentData, amount: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Date *</label>
                                <input type="date" required className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500" value={paymentData.date} onChange={(e) => setPaymentData({ ...paymentData, date: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Payment Method</label>
                                <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500 bg-white" value={paymentData.method} onChange={(e) => setPaymentData({ ...paymentData, method: e.target.value })}>
                                    <option value="CASH">Cash</option>
                                    <option value="BANK_TRANSFER">Bank Transfer</option>
                                    <option value="UPI">UPI / Online</option>
                                    <option value="CHEQUE">Cheque</option>
                                </select>
                            </div>
                            <div className="pt-4 flex justify-end gap-3 border-t">
                                <button type="button" onClick={() => setIsPaymentModalOpen(false)} className="px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-100 rounded-lg">Cancel</button>
                                <button type="submit" className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white text-sm font-medium rounded-lg">Save Payment</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Plus, Save, Download, Trash2, Printer, Search, Lock, Unlock, ChevronUp, ChevronDown, Users, Layout, Settings, Type, Image, FileText, ZoomIn, ZoomOut, MousePointer2 } from 'lucide-react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { useUI } from '../../context/UIContext';
import api from '../../services/api';
import InvoiceRenderer from '../../components/invoice-builder/InvoiceRenderer';
import toast from 'react-hot-toast';
import html2pdf from 'html2pdf.js';
import { injectPdfColorFix } from '../../utils/pdfColorFix';

export default function InvoiceBuilder({ invoiceId: propId, onClose, startEditing = false }) {
    const navigate = useNavigate();
    const { id: paramId } = useParams();
    const { alert, prompt } = useUI();
    const [searchParams] = useSearchParams();
    const templateIdFromUrl = searchParams.get('templateId');
    const id = propId || paramId;

    const [loading, setLoading] = useState(true);
    const [isEditing, setIsEditing] = useState(startEditing || !id);
    const [companyConfig, setCompanyConfig] = useState(null);
    const [templates, setTemplates] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [inventory, setInventory] = useState([]);

    const [showCustomerModal, setShowCustomerModal] = useState(false);
    const [newCustomer, setNewCustomer] = useState({ name: '', phone: '', address: '', taxId: '' });

    const [activeLayout, setActiveLayout] = useState([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState('');
    const [zoom, setZoom] = useState(0.8);
    const [sidebarTab, setSidebarTab] = useState('elements'); // 'elements', 'settings', 'data'

    const [invoiceData, setInvoiceData] = useState({
        invoiceNumber: 'INV-LOADING',
        customerId: '',
        customerName: '',
        clientAddress: '',
        gstNumber: '',
        date: new Date().toISOString().slice(0, 10),
        items: [],
        status: 'DRAFT',
        taxRate: 10,
        customAttributes: []
    });

    const canvasRef = useRef(null);

    const handleDownloadPDF = useCallback(async () => {
        const el = canvasRef.current;
        if (!el) return toast.error('Canvas not ready');
        try {
            toast.loading('Generating PDF...', { id: 'pdf-gen' });
            await html2pdf().set({
                margin: 0,
                filename: `Invoice-${invoiceData.invoiceNumber || 'draft'}.pdf`,
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: {
                    scale: 2,
                    useCORS: true,
                    logging: false,
                    onclone: (clonedDoc) => injectPdfColorFix(clonedDoc),
                },
                jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
            }).from(el).save();
            toast.success('PDF downloaded!', { id: 'pdf-gen' });
        } catch {
            toast.error('Failed to generate PDF', { id: 'pdf-gen' });
        }
    }, [invoiceData.invoiceNumber]);

    const DEFAULT_LAYOUT = [
        { id: 'b0', type: 'COMPANY_NAME', config: { x: 40, y: 60, width: 300, height: 40, fontSize: 24, fontWeight: 'bold' } },
        { id: 'b1', type: 'COMPANY_DETAILS', config: { x: 40, y: 100, width: 300, height: 80, fontSize: 12 } },
        { id: 'b2', type: 'CUSTOMER_DETAILS', config: { x: 40, y: 300, width: 300, height: 120, fontSize: 13 } },
        { id: 'b3', type: 'INVOICE_DETAILS', config: { x: 500, y: 60, width: 250, height: 100, fontSize: 12, textAlign: 'right' } },
        { id: 'b4', type: 'ITEMS_TABLE', config: { x: 40, y: 450, width: 710, height: 300 } },
        { id: 'b5', type: 'TOTALS', config: { x: 500, y: 760, width: 250, height: 150 } },
        { id: 'b6', type: 'CUSTOM_ATTRIBUTES', config: { x: 40, y: 760, width: 440, height: 150 } }
    ];

    useEffect(() => {
        const fetchData = async () => {
            try {
                const companyId = localStorage.getItem('companyId');
                const [configRes, templatesRes, customersRes, inventoryRes] = await Promise.all([
                    api.get('/company/config'),
                    api.get('/invoice-templates', { params: { companyId } }),
                    api.get('/customers', { params: { companyId } }),
                    api.get('/inventory', { params: { companyId } })
                ]);

                setCompanyConfig(configRes.data.company);
                setTemplates(templatesRes.data);
                const fetchedCustomers = customersRes.data;
                setCustomers(fetchedCustomers);
                setInventory(inventoryRes.data);

                if (id) {
                    // --- Loading existing invoice ---
                    const invRes = await api.get(`/invoices/${id}`);
                    const data = invRes.data;
                    // eslint-disable-next-line no-unused-vars
                    const cleansedItems = (data.items || []).map(({ id: _i, invoiceId: _ii, customFields: _cf, invoice: _inv, inventory: _invent, ...rest }) => rest);
                    setInvoiceData({
                        invoiceNumber: data.invoiceNumber || '',
                        customerId: data.customerId || '',
                        customerName: data.customerName || '',
                        clientAddress: data.clientAddress || '',
                        gstNumber: data.gstNumber || '',
                        date: data.date ? new Date(data.date).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10),
                        notes: typeof data.notes === 'string' ? data.notes : '',
                        items: cleansedItems,
                        status: data.status || 'DRAFT',
                        taxRate: data.taxRate !== undefined ? data.taxRate : 10,
                        customAttributes: Array.isArray(data.customAttributes) ? data.customAttributes : [],
                        templateId: data.templateId || '',
                    });
                    const rawLayout = data.layout;
                    const safeLayout = Array.isArray(rawLayout)
                        ? rawLayout
                        : typeof rawLayout === 'string'
                            ? (() => { try { return JSON.parse(rawLayout); } catch { return []; } })()
                            : [];
                    if (safeLayout.length > 0) setActiveLayout(safeLayout);
                    if (data.templateId) setSelectedTemplateId(data.templateId);
                } else {
                    // --- New invoice ---
                    // Fetch sequential invoice number from backend
                    let nextNum = '';
                    try {
                        const numRes = await api.get('/invoices/next-number', { params: { companyId } });
                        nextNum = numRes.data.invoiceNumber;
                    } catch {
                        nextNum = `INV-${Date.now().toString().slice(-6)}`;
                    }

                    // Check for customerId in URL
                    const urlCustomerId = searchParams.get('customerId');
                    let preselectedCustomer = null;
                    if (urlCustomerId) {
                        preselectedCustomer = fetchedCustomers.find(c => (c.id === urlCustomerId || c._id === urlCustomerId));
                    }

                    setInvoiceData(prev => ({
                        ...prev,
                        invoiceNumber: nextNum,
                        customerId: preselectedCustomer ? (preselectedCustomer.id || preselectedCustomer._id) : prev.customerId,
                        customerName: preselectedCustomer ? preselectedCustomer.name : prev.customerName,
                        clientAddress: preselectedCustomer ? preselectedCustomer.address : prev.clientAddress
                    }));

                    // Apply template layout
                    if (templateIdFromUrl) {
                        const temp = templatesRes.data.find(t => (t.id || t._id) === templateIdFromUrl);
                        if (temp) {
                            setActiveLayout(temp.layout);
                            setSelectedTemplateId(temp.id || temp._id);
                        } else {
                            setActiveLayout(DEFAULT_LAYOUT);
                        }
                    } else if (templatesRes.data.length > 0) {
                        setActiveLayout(templatesRes.data[0].layout);
                        setSelectedTemplateId(templatesRes.data[0].id || templatesRes.data[0]._id);
                    } else {
                        setActiveLayout(DEFAULT_LAYOUT);
                    }
                }

                setLoading(false);
            } catch {
                setLoading(false);
            }
        };
        fetchData();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [id, templateIdFromUrl, searchParams]);

    const handleUpdateData = useCallback((field, value) => {
        setInvoiceData(prev => ({ ...prev, [field]: value }));
    }, []);

    const handleUpdateConfig = useCallback((blockId, key, value) => {
        setActiveLayout(prev => prev.map(b => b.id === blockId ? { ...b, config: { ...b.config, [key]: value } } : b));
    }, []);

    const calculateSubtotal = () => (invoiceData.items || []).reduce((sum, item) => sum + (item.total || 0), 0);
    const tax = calculateSubtotal() * (invoiceData.taxRate / 100);
    const total = calculateSubtotal() + tax;

    const handleSave = async (status = 'DRAFT') => {
        try {
            if (!invoiceData.customerId) {
                return toast.error("Please select a customer first");
            }

            const companyId = localStorage.getItem('companyId');

            // If no blocks on canvas, snapshot from the selected template
            const layoutToSave = activeLayout.length > 0
                ? activeLayout
                : templates.find(t => (t.id || t._id) === selectedTemplateId)?.layout || [];

            const payload = {
                ...invoiceData,
                companyId,
                status,
                grandTotal: total,
                layout: layoutToSave,
                templateId: selectedTemplateId || invoiceData.templateId
            };

            // Ensure attributes are always an array
            if (!Array.isArray(payload.customAttributes)) payload.customAttributes = [];

            if (id) {
                await api.patch(`/invoices/${id}`, payload);
            } else {
                await api.post('/invoices', payload);
            }

            toast.success(`Invoice ${status === 'DRAFT' ? 'saved' : 'issued'} successfully!`);
            if (onClose) onClose();
            else navigate('/dashboard/invoicing');
        } catch (err) {
            console.error("Save Error:", err);
            alert("Save Failed", err.response?.data?.message || err.message, "error");
        }
    };

    if (loading) return <div className="flex h-full items-center justify-center">Loading Invoice Builder...</div>;

    return (
        <div className="flex flex-col h-[calc(100vh-140px)] bg-slate-100 overflow-hidden rounded-b-2xl">
            {/* Top Toolbar */}
            <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-30 shadow-sm">
                <div className="flex items-center gap-6">
                    <div className="flex items-center gap-2 bg-slate-50 p-1 rounded-lg border border-slate-200">
                        <button onClick={() => setZoom(prev => Math.max(0.3, prev - 0.1))} className="p-1.5 hover:bg-slate-200 rounded transition-colors"><ZoomOut size={16} className="text-slate-600" /></button>
                        <span className="text-xs font-bold text-slate-700 w-12 text-center">{Math.round(zoom * 100)}%</span>
                        <button onClick={() => setZoom(prev => Math.min(1.5, prev + 0.1))} className="p-1.5 hover:bg-slate-200 rounded transition-colors"><ZoomIn size={16} className="text-slate-600" /></button>
                    </div>

                    <div className="h-6 w-px bg-slate-200"></div>

                    <div className="flex items-center gap-3">
                        <label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Active Template</label>
                        <select
                            className="bg-slate-50 text-slate-900 text-xs font-bold px-3 py-1.5 rounded border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={selectedTemplateId}
                            onChange={(e) => {
                                const t = templates.find(temp => (temp.id || temp._id) === e.target.value);
                                if (t) {
                                    setActiveLayout(t.layout || []);
                                    setSelectedTemplateId(t.id || t._id);
                                    handleUpdateData('templateId', t.id || t._id);

                                    if (!id) {
                                        setInvoiceData(prev => ({
                                            ...prev,
                                            taxRate: t.taxRate !== undefined ? t.taxRate : 10,
                                            notes: t.notes || prev.notes,
                                            items: t.items?.length > 0 ? t.items.map(item => ({ ...item })) : [],
                                            customAttributes: t.layout?.find(b => b.type === 'CUSTOM_ATTRIBUTES')?.config?.attributes || []
                                        }));
                                    }
                                }
                            }}
                        >
                            <option value="">Select Template...</option>
                            {templates.map(t => <option key={t.id || t._id} value={t.id || t._id}>{t.name || '(Unnamed Template)'}</option>)}
                        </select>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button
                        onClick={handleDownloadPDF}
                        className="flex items-center gap-2 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg text-sm font-bold hover:bg-slate-50 transition-all active:scale-95"
                    >
                        <Download size={16} /> Download PDF
                    </button>
                    {!isEditing && id ? (
                        <button
                            onClick={async () => {
                                const inputPass = await prompt(
                                    'Security Authorization',
                                    'Enter Security Password to Edit Invoice:',
                                    'password',
                                    'Verify Password',
                                    'primary'
                                );
                                if (!inputPass) return;
                                try {
                                    const companyId = localStorage.getItem('companyId');
                                    const res = await api.post('/company/verify-password', { password: inputPass, companyId });
                                    if (!res.data.valid) {
                                        await alert('Access Denied', 'Incorrect Password! You cannot edit this invoice.', 'error');
                                        return;
                                    }
                                    setIsEditing(true);
                                } catch (err) {
                                    await alert('Error', 'Password verification failed.', 'error');
                                }
                            }}
                            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 shadow-md transition-all active:scale-95"
                        >
                            <Unlock size={16} /> Edit Mode
                        </button>
                    ) : (
                        <>
                            <button onClick={() => handleSave('DRAFT')} className="px-4 py-2 text-slate-500 text-sm font-bold hover:text-indigo-600 transition-colors">Save Draft</button>
                            <button onClick={() => handleSave('ISSUED')} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-black uppercase tracking-wider hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all active:scale-95">
                                <Save size={18} /> Issue Invoice
                            </button>
                        </>
                    )}
                </div>
            </div>

            <div className="flex flex-1 overflow-hidden">
                {/* Left Controls */}
                <div className="w-80 bg-white border-r border-slate-200 flex flex-col shrink-0 z-20">
                    <div className="flex border-b border-slate-200 bg-slate-50/50">
                        <button onClick={() => setSidebarTab('elements')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${sidebarTab === 'elements' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-white' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}>Layout Elements</button>
                        <button onClick={() => setSidebarTab('data')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${sidebarTab === 'data' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-white' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}>Invoice Data</button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                        {sidebarTab === 'elements' && (
                            <div className="space-y-6">
                                <div>
                                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Structure</h4>
                                    <div className="p-4 bg-indigo-50/50 border border-indigo-100 rounded-xl text-[11px] text-indigo-700 leading-relaxed">
                                        <strong>Real-time Designer:</strong> Most elements can be edited directly on the canvas. Drag blocks to reposition, or use the designer to modify the template.
                                    </div>
                                </div>
                            </div>
                        )}

                        {sidebarTab === 'data' && (
                            <div className="space-y-6">
                                <div className="space-y-4">
                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b border-slate-100 pb-2">Client Selection</h4>
                                        <div className="flex flex-col gap-2">
                                            <select
                                                className="w-full bg-slate-50 border border-slate-200 text-xs text-slate-900 rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                                                value={invoiceData.customerId || ''}
                                                onChange={(e) => {
                                                    const val = e.target.value;
                                                    const c = customers.find(cust => (cust.id === val || cust._id === val));
                                                    if (c) {
                                                        setInvoiceData(prev => ({
                                                            ...prev,
                                                            customerId: c.id || c._id,
                                                            customerName: c.name,
                                                            clientAddress: c.address
                                                        }));
                                                    }
                                                }}
                                            >
                                                <option value="">Select Existing Client...</option>
                                                {customers.map(c => <option key={c.id || c._id} value={c.id || c._id}>{c.name}</option>)}
                                            </select>
                                            <button onClick={() => setShowCustomerModal(true)} className="w-full py-2.5 border border-dashed border-slate-300 text-slate-500 text-[10px] font-bold uppercase rounded-lg hover:border-indigo-500 hover:text-indigo-600 hover:bg-slate-50 transition-all">+ Quick Add Client</button>
                                        </div>
                                    </div>

                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b border-slate-100 pb-2">Add Products</h4>
                                        <select
                                            className="w-full bg-slate-50 border border-slate-200 text-xs text-slate-900 rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                                            onChange={(e) => {
                                                const p = inventory.find(inv => inv.id === e.target.value);
                                                if (p) {
                                                    const newItem = { description: p.name, quantity: 1, price: p.sellingPrice, total: p.sellingPrice, inventoryId: p.id };
                                                    handleUpdateData('items', [...(invoiceData.items || []), newItem]);
                                                }
                                            }}
                                        >
                                            <option value="">Choose Inventory Item...</option>
                                            {inventory.map(inv => <option key={inv.id} value={inv.id}>{inv.name} (₹{inv.sellingPrice})</option>)}
                                        </select>
                                    </div>

                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b border-slate-100 pb-2">Invoice Configuration</h4>
                                        <div className="space-y-4">
                                            <div>
                                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider block mb-1.5 ml-1">Invoice Number</label>
                                                <input type="text" className="w-full bg-slate-50 border border-slate-200 p-2.5 text-slate-900 rounded-lg text-xs focus:ring-2 focus:ring-indigo-500 outline-none" value={invoiceData.invoiceNumber} onChange={e => handleUpdateData('invoiceNumber', e.target.value)} />
                                            </div>
                                            <div>
                                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider block mb-1.5 ml-1">Invoice Date</label>
                                                <input type="date" className="w-full bg-slate-50 border border-slate-200 p-2.5 text-slate-900 rounded-lg text-xs focus:ring-2 focus:ring-indigo-500 outline-none" value={invoiceData.date} onChange={e => handleUpdateData('date', e.target.value)} />
                                            </div>
                                        </div>
                                    </div>

                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b border-slate-100 pb-2">Predefined Fields</h4>
                                        <div className="p-3 bg-slate-50 border border-slate-100 rounded-lg">
                                            <p className="text-[10px] text-slate-500 italic leading-relaxed">
                                                Custom fields (like Tax ID, Status, etc.) are defined in the <strong>Template Designer</strong>.
                                                Fill their values directly on the invoice canvas.
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )
                        }
                    </div>

                    <div className="p-6 bg-slate-50 border-t border-slate-200">
                        <div className="flex flex-col gap-1.5 mb-4">
                            <div className="flex justify-between text-xs text-slate-500 font-medium"><span>Subtotal</span><span>₹{calculateSubtotal().toFixed(2)}</span></div>
                            <div className="flex justify-between text-xs text-slate-500 font-medium"><span>Tax ({invoiceData.taxRate}%)</span><span>₹{tax.toFixed(2)}</span></div>
                        </div>
                        <div className="h-px bg-slate-200 mb-4 opacity-50"></div>
                        <div className="flex justify-between items-center text-slate-900 font-black text-xl">
                            <span>TOTAL</span>
                            <span className="text-indigo-600">₹{total.toFixed(2)}</span>
                        </div>
                    </div>
                </div>

                {/* Canvas Workspace */}
                <div className="flex-1 overflow-auto bg-slate-100/50 p-12 flex justify-center items-start relative custom-scrollbar">
                    {/* Visual Backdrop Effects */}
                    <div className="absolute inset-0 opacity-40 pointer-events-none bg-[radial-gradient(circle_at_center,rgba(99,102,241,0.05)_0,transparent_70%)]"></div>

                    <div className="relative group/canvas" style={{ transform: `scale(${zoom})`, transformOrigin: 'top center' }}>

                        <div ref={canvasRef} className="shadow-[0_40px_120px_rgba(0,0,0,0.08)] transition-all duration-500 rounded-sm">
                            <InvoiceRenderer
                                editable={isEditing}
                                layout={activeLayout}
                                invoiceData={invoiceData}
                                companyConfig={companyConfig}
                                taxRate={invoiceData.taxRate}
                                calculateSubtotal={calculateSubtotal}
                                tax={tax}
                                total={total}
                                onUpdateData={handleUpdateData}
                                onUpdateConfig={handleUpdateConfig}
                                options={{ inventory }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Quick Create Customer Modal */}
            {showCustomerModal && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-md flex items-center justify-center z-[100] p-4">
                    <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl shadow-slate-900/20 overflow-hidden animate-in zoom-in duration-300 border border-slate-100">

                        {/* Header */}
                        <div className="relative px-7 pt-7 pb-6 bg-gradient-to-br from-indigo-600 via-indigo-700 to-violet-700 overflow-hidden">
                            <div className="absolute -top-6 -right-6 w-32 h-32 bg-white/5 rounded-full" />
                            <div className="absolute -bottom-8 -left-4 w-24 h-24 bg-white/5 rounded-full" />
                            <div className="relative flex items-center gap-4">
                                <div className="p-3 bg-white/15 backdrop-blur-sm rounded-xl border border-white/20 shadow-inner">
                                    <Users size={22} className="text-white" strokeWidth={2.5} />
                                </div>
                                <div>
                                    <h2 className="text-xl font-black text-white tracking-tight">New Client</h2>
                                    <p className="text-indigo-200 text-xs font-medium mt-0.5">Fill in the client details below</p>
                                </div>
                            </div>
                        </div>

                        {/* Body */}
                        <div className="px-7 py-6 space-y-5">
                            {/* Business Name */}
                            <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                                    Business Name <span className="text-red-400">*</span>
                                </label>
                                <input
                                    type="text"
                                    placeholder="e.g. Acme Corp"
                                    className="w-full bg-slate-50 border border-slate-200 px-4 py-3 text-sm text-slate-900 rounded-xl placeholder:text-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all font-medium"
                                    value={newCustomer.name}
                                    onChange={e => setNewCustomer({ ...newCustomer, name: e.target.value })}
                                />
                            </div>

                            {/* Phone + GSTIN side by side */}
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1">
                                        Phone <span className="text-red-400">*</span>
                                    </label>
                                    <input
                                        type="tel"
                                        placeholder="+91 98765 43210"
                                        className="w-full bg-slate-50 border border-slate-200 px-4 py-3 text-sm text-slate-900 rounded-xl placeholder:text-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all font-medium"
                                        value={newCustomer.phone}
                                        onChange={e => setNewCustomer({ ...newCustomer, phone: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                        GSTIN
                                    </label>
                                    <input
                                        type="text"
                                        placeholder="22AAAAA0000A1Z5"
                                        className="w-full bg-slate-50 border border-slate-200 px-4 py-3 text-sm text-slate-900 rounded-xl placeholder:text-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all font-medium uppercase"
                                        value={newCustomer.taxId || ''}
                                        onChange={e => setNewCustomer({ ...newCustomer, taxId: e.target.value })}
                                    />
                                </div>
                            </div>

                            {/* Address */}
                            <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                    Business Address
                                </label>
                                <textarea
                                    placeholder="Street, City, State, ZIP"
                                    className="w-full bg-slate-50 border border-slate-200 px-4 py-3 text-sm text-slate-900 rounded-xl placeholder:text-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none font-medium"
                                    rows={2}
                                    value={newCustomer.address}
                                    onChange={e => setNewCustomer({ ...newCustomer, address: e.target.value })}
                                />
                            </div>
                        </div>

                        {/* Footer */}
                        <div className="px-7 py-5 bg-slate-50 border-t border-slate-100 flex items-center justify-between gap-3">
                            <button
                                onClick={() => setShowCustomerModal(false)}
                                className="px-5 py-2.5 text-sm font-bold text-slate-500 bg-white border border-slate-200 rounded-xl hover:bg-slate-100 hover:text-slate-700 transition-all active:scale-95"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={async () => {
                                    try {
                                        const cid = localStorage.getItem('companyId');
                                        const res = await api.post('/customers', { companyId: cid, ...newCustomer });
                                        setCustomers([...customers, res.data]);
                                        handleUpdateData('customerId', res.data.id || res.data._id);
                                        handleUpdateData('customerName', res.data.name);
                                        handleUpdateData('clientAddress', res.data.address);
                                        setShowCustomerModal(false);
                                        toast.success("Client added!");
                                    } catch { toast.error("Failed to add client"); }
                                }}
                                className="flex items-center gap-2 px-6 py-2.5 bg-gradient-to-r from-indigo-600 to-violet-600 text-white text-sm font-black rounded-xl hover:from-indigo-700 hover:to-violet-700 shadow-lg shadow-indigo-200 transition-all active:scale-95"
                            >
                                <Users size={15} />
                                Add &amp; Apply
                            </button>
                        </div>
                    </div>
                </div>
            )}

        </div>
    );
}

